338→export async function loadWorkspaceKindCandidates(
339→  surreal: Surreal,
340→  workspaceRecord: RecordId<"workspace", string>,
341→  kind: ExtractableEntityKind,
342→): Promise<CandidateEntityRow[]> {
343→  if (kind === "project") {
344→    const [rows] = await surreal
345→      .query<[CandidateEntityRow[]]>(
346→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
347→        { workspace: workspaceRecord },
348→      )
349→      .collect<[CandidateEntityRow[]]>();
350→    return rows;
351→  }
352→
353→  if (kind === "person") {
354→    const [rows] = await surreal
355→      .query<[CandidateEntityRow[]]>(
356→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
357→        { workspace: workspaceRecord },
358→      )
359→      .collect<[CandidateEntityRow[]]>();
360→    return rows;
361→  }
362→
363→  if (kind === "feature") {
364→    const [rows] = await surreal
365→      .query<[CandidateEntityRow[]]>(
366→        [
367→          "SELECT id, name AS text, embedding",
368→          "FROM feature",
369→          "WHERE id IN (",
370→          "  SELECT VALUE out",
371→          "  FROM has_feature",
372→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
373→          ");",
374→        ].join(" "),
375→        { workspace: workspaceRecord },
376→      )
377→      .collect<[CandidateEntityRow[]]>();
378→    return rows;
379→  }
380→
381→  if (kind === "task") {
382→    const [rows] = await surreal
383→      .query<[CandidateEntityRow[]]>(
384→        [
385→          "SELECT id, title AS text, embedding",
386→          "FROM task",
387→          "WHERE id IN (",
388→          "  SELECT VALUE `in`",
389→          "  FROM belongs_to",
390→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
391→          ")",
392→          "OR source_message IN (",
393→          "  SELECT VALUE id",
394→          "  FROM message",
395→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
396→          ")",
397→          "OR source_commit IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace);",
398→        ].join(" "),
399→        { workspace: workspaceRecord },
400→      )
401→      .collect<[CandidateEntityRow[]]>();
402→    return uniqueCandidateRows(rows);
403→  }
404→
405→  if (kind === "decision") {
406→    const [rows] = await surreal
407→      .query<[CandidateEntityRow[]]>(
408→        [
