  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import { z } from "zod";
  4→import { ENTITY_CATEGORIES } from "../../shared/contracts";
  5→import { HttpError } from "../http/errors";
  6→import { logError, logInfo } from "../http/observability";
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { createEmbeddingVector } from "../graph/embeddings";
  9→import { resolveWorkspaceProjectRecord } from "../graph/queries";
 10→import { ensureProjectFeatureEdge } from "../workspace/workspace-scope";
 11→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 12→import type { ServerDependencies } from "../runtime/types";
 13→import { seedDescriptionEntry } from "../descriptions/persist";
 14→import { fireDescriptionUpdates } from "../descriptions/triggers";
 15→
 16→const acceptWorkItemSchema = z.object({
 17→  kind: z.enum(["task", "feature"]),
 18→  title: z.string().min(1),
 19→  rationale: z.string().min(1),
 20→  project: z.string().optional(),
 21→  priority: z.string().optional(),
 22→  category: z.enum(ENTITY_CATEGORIES).optional(),
 23→});
 24→
 25→export function createWorkItemAcceptHandler(
 26→  deps: ServerDependencies,
 27→): (workspaceId: string, request: Request) => Promise<Response> {
 28→  return (workspaceId: string, request: Request) =>
 29→    handleAcceptWorkItem(deps, workspaceId, request);
 30→}
 31→
 32→async function handleAcceptWorkItem(
 33→  deps: ServerDependencies,
 34→  workspaceId: string,
 35→  request: Request,
 36→): Promise<Response> {
 37→  let body: unknown;
 38→  try {
 39→    body = await request.json();
 40→  } catch {
 41→    return jsonError("invalid JSON body", 400);
 42→  }
 43→
 44→  const parsed = acceptWorkItemSchema.safeParse(body);
 45→  if (!parsed.success) {
 46→    return jsonError(`invalid work item: ${parsed.error.message}`, 400);
 47→  }
 48→
 49→  const item = parsed.data;
 50→
 51→  let workspaceRecord: RecordId<"workspace", string>;
 52→  try {
 53→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 54→  } catch (error) {
 55→    if (error instanceof HttpError) {
 56→      return jsonError(error.message, error.status);
 57→    }
 58→    logError("work-item.accept.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 59→    return jsonError("failed to resolve workspace", 500);
 60→  }
 61→
 62→  try {
 63→    const now = new Date();
 64→    const embedding = await createEmbeddingVector(
 65→      deps.embeddingModel,
 66→      item.title,
 67→      deps.config.embeddingDimension,
 68→    );
 69→
 70→    const entityId = randomUUID();
 71→
 72→    if (item.kind === "task") {
 73→      const taskRecord = new RecordId("task", entityId);
 74→      await deps.surreal.create(taskRecord).content({
 75→        title: item.title,
 76→        status: "open",
 77→        ...(item.category ? { category: item.category } : {}),
 78→        ...(item.priority ? { priority: item.priority } : {}),
 79→        ...(embedding ? { embedding } : {}),
 80→        created_at: now,
 81→        updated_at: now,
 82→      });
 83→
 84→      if (item.project) {
 85→        try {
 86→          const projectRecord = await resolveWorkspaceProjectRecord({
 87→            surreal: deps.surreal,
 88→            workspaceRecord,
 89→            projectInput: item.project,
 90→          });
 91→          await deps.surreal
 92→            .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
 93→              added_at: now,
 94→            })
 95→            .output("after");
 96→        } catch {
 97→          // project resolution is best-effort; task still created
 98→        }
 99→      }
100→
101→      void seedDescriptionEntry({
102→        surreal: deps.surreal,
103→        targetRecord: taskRecord,
104→        text: item.rationale,
105→      }).catch(() => undefined);
106→
107→      logInfo("work-item.accept.task.created", "Task created from work item suggestion", {
108→        workspaceId,
109→        entityId,
110→        title: item.title,
111→      });
112→
113→      return jsonResponse({ entityId: `task:${entityId}` }, 201);
114→    }
115→
