type EntityRelationRow = {
  id: RecordId<"entity_relation", string>;
  in: GraphEntityRecord;
  out: GraphEntityRecord;
  kind: string;
  confidence: number;
};

async function collectEntityRelationEdges(
  surreal: Surreal,
  entityIds: RecordId<string, string>[],
): Promise<GraphViewRawEdge[]> {
  if (entityIds.length === 0) {
    return [];
  }

  const [rows] = await surreal
    .query<[EntityRelationRow[]]>(
      [
        "SELECT id, `in`, out, kind, confidence",
        "FROM entity_relation",
        "WHERE `in` IN $entityIds AND out IN $entityIds;",
      ].join(" "),
      { entityIds },
    )
    .collect<[EntityRelationRow[]]>();

  return rows.map((row) => ({
    id: toRecordIdString(row.id),
    fromId: toRecordIdString(row.in),
    toId: toRecordIdString(row.out),
    kind: row.kind,
    confidence: row.confidence,
  }));
}

async function resolveEntityNames(
  surreal: Surreal,
  records: GraphEntityRecord[],
): Promise<GraphViewRawEntity[]> {
  const entities: GraphViewRawEntity[] = [];

  for (const record of records) {
    const name = await readEntityName(surreal, record);
    if (!name) {
      continue;
    }

    entities.push({
      id: toRecordIdString(record),
      kind: record.table.name as GraphEntityTable,
      name,
    });
  }

  return entities;
}

export async function getProjectGraphView(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  projectRecord: RecordId<"project", string>;
}): Promise<GraphViewRawResult> {
  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.projectRecord);
  if (!scoped) {
    throw new Error("project is outside the current workspace scope");
  }

  const allRecords: GraphEntityRecord[] = [input.projectRecord as GraphEntityRecord];
  const seen = new Set<string>();
  seen.add(toRecordIdString(input.projectRecord));

  const addRecord = (record: GraphEntityRecord) => {
    const key = toRecordIdString(record);
    if (!seen.has(key)) {
      seen.add(key);
      allRecords.push(record);
    }
  };

  // Features via has_feature
  const [featureRows] = await input.surreal
    .query<[Array<RecordId<"feature", string>>]>(
      "SELECT VALUE out FROM has_feature WHERE `in` = $project;",
      { project: input.projectRecord },
    )
    .collect<[Array<RecordId<"feature", string>>]>();

  for (const record of featureRows) {
    addRecord(record as GraphEntityRecord);
  }

  // Tasks/decisions/questions via belongs_to WHERE out = project
  const [belongsToRows] = await input.surreal
    .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
      "SELECT VALUE `in` FROM belongs_to WHERE out = $project;",
      { project: input.projectRecord },
    )
    .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();

  for (const record of belongsToRows) {
    addRecord(record as GraphEntityRecord);
  }

  // Tasks via features' has_task + decisions/questions that belong_to features
  if (featureRows.length > 0) {
    const [featureTaskRows] = await input.surreal
      .query<[Array<RecordId<"task", string>>]>(
        "SELECT VALUE out FROM has_task WHERE `in` IN $features;",
        { features: featureRows },
      )
      .collect<[Array<RecordId<"task", string>>]>();

    for (const record of featureTaskRows) {
      addRecord(record as GraphEntityRecord);
    }

    const [featureBelongsRows] = await input.surreal
      .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
        "SELECT VALUE `in` FROM belongs_to WHERE out IN $features;",
        { features: featureRows },
      )
      .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();

    for (const record of featureBelongsRows) {
      addRecord(record as GraphEntityRecord);
    }
  }

  // Entities extracted from workspace messages (catches decisions/questions/tasks without belongs_to edges)
  const [provenanceRows] = await input.surreal
    .query<[Array<GraphEntityRecord>]>(
      [
        "SELECT VALUE out FROM extraction_relation",
        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace));",
      ].join(" "),
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<GraphEntityRecord>]>();

  for (const record of provenanceRows) {
    const table = record.table.name;
    if (table === "task" || table === "decision" || table === "question" || table === "feature" || table === "person") {
      addRecord(record as GraphEntityRecord);
    }
  }

  // Persons via member_of WHERE out = workspace
  const [personRows] = await input.surreal
    .query<[Array<RecordId<"person", string>>]>(
      "SELECT VALUE `in` FROM member_of WHERE out = $workspace;",
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<RecordId<"person", string>>]>();

  for (const record of personRows) {
    addRecord(record as GraphEntityRecord);
  }

  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

export async function getFocusedGraphView(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  centerEntityRecord: GraphEntityRecord;
  depth: number;
}): Promise<GraphViewRawResult> {
  const clampedDepth = Math.max(1, Math.min(3, input.depth));

  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
  if (!scoped) {
    throw new Error("entity is outside the current workspace scope");
  }

  const collected = new Map<string, GraphEntityRecord>();
  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);

  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];

  for (let hop = 0; hop < clampedDepth; hop++) {
    if (frontier.length === 0) {
      break;
    }

    const [rows] = await input.surreal
      .query<[EntityRelationRow[]]>(
        [
          "SELECT id, `in`, out, kind, confidence",
          "FROM entity_relation",
          "WHERE `in` IN $currentIds OR out IN $currentIds;",
        ].join(" "),
        { currentIds: frontier },
      )
      .collect<[EntityRelationRow[]]>();

    const nextFrontier: RecordId<string, string>[] = [];

    for (const row of rows) {
      for (const endpoint of [row.in, row.out]) {
        const key = toRecordIdString(endpoint);
        if (collected.has(key)) {
          continue;
        }

        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint);
        if (!inScope) {
          continue;
        }

        collected.set(key, endpoint);
        nextFrontier.push(endpoint);
      }
    }

    frontier = nextFrontier;
  }

  const allRecords = Array.from(collected.values());
  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

export async function getWorkspaceGraphOverview(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
}): Promise<GraphViewRawResult> {
  // Projects via has_project
  const [projectRows] = await input.surreal
    .query<[Array<RecordId<"project", string>>]>(
      "SELECT VALUE out FROM has_project WHERE `in` = $workspace;",
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<RecordId<"project", string>>]>();

  const allRecords: GraphEntityRecord[] = [];

  for (const record of projectRows) {
    allRecords.push(record as GraphEntityRecord);
  }

  // Features via has_feature for each project
  if (projectRows.length > 0) {
    const [featureRows] = await input.surreal
      .query<[Array<RecordId<"feature", string>>]>(
        "SELECT VALUE out FROM has_feature WHERE `in` IN $projects;",
        { projects: projectRows },
      )
      .collect<[Array<RecordId<"feature", string>>]>();

    for (const record of featureRows) {
      allRecords.push(record as GraphEntityRecord);
    }
  }

  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

import { tool } from "ai";
import { z } from "zod";
import {
  createDecisionRecord,
  createExtractionProvenanceEdge,
  resolveWorkspaceFeatureRecord,
  resolveWorkspaceProjectRecord,
} from "../../graph/queries";
import { requireToolContext } from "./helpers";
import type { ChatToolDeps } from "./types";

export function createCreateProvisionalDecisionTool(deps: ChatToolDeps) {
  return tool({
    description:
      "Create a provisional decision when no existing answer exists. Use after resolve_decision returns unresolved and the user wants to proceed.",
    inputSchema: z.object({
      name: z.string().min(1).describe("Concise decision name"),
      rationale: z.string().min(1).describe("Why this decision was made"),
      context: z
        .object({
          project: z.string().optional(),
          feature: z.string().optional(),
        })
        .optional(),
      options_considered: z.array(z.string().min(1)).optional(),
    }),
    execute: async (input, options) => {
      const context = requireToolContext(options);
      const now = new Date();

      const projectRecord = input.context?.project
        ? await resolveWorkspaceProjectRecord({
            surreal: deps.surreal,
            workspaceRecord: context.workspaceRecord,
            projectInput: input.context.project,
          })
        : undefined;

      const featureRecord = input.context?.feature
        ? await resolveWorkspaceFeatureRecord({
            surreal: deps.surreal,
            workspaceRecord: context.workspaceRecord,
            featureInput: input.context.feature,
          })
        : undefined;

      const decisionRecord = await createDecisionRecord({
        surreal: deps.surreal,
        summary: input.name,
        status: "provisional",
        now,
        sourceMessageRecord: context.currentMessageRecord,
        rationale: input.rationale,
        ...(input.options_considered && input.options_considered.length > 0
          ? { optionsConsidered: input.options_considered }
          : {}),
        decidedByName: "chat_agent",
        ...(projectRecord ? { projectRecord } : {}),
        ...(featureRecord ? { featureRecord } : {}),
      });

      await createExtractionProvenanceEdge({
        surreal: deps.surreal,
        sourceRecord: context.currentMessageRecord,
        targetRecord: decisionRecord,
        now,
        confidence: 0.9,
        model: deps.extractionModelId,
        fromText: input.name,
        evidence: context.latestUserText,
        evidenceSourceRecord: context.currentMessageRecord,
      });

      return {
        decision_id: `decision:${decisionRecord.id as string}`,
        status: "provisional",
        review_required: true,
      };
    },
  });
}

import { tool } from "ai";
import { z } from "zod";
import { createEmbeddingVector } from "../../graph/embeddings";
import {
  createDecisionRecord,
  createExtractionProvenanceEdge,
  getDecisionPrimarySourceMessage,
  listDecisionConstraintCandidates,
  parseRecordIdString,
  resolveWorkspaceFeatureRecord,
  resolveWorkspaceProjectRecord,
  type GraphEntityRecord,
} from "../../graph/queries";
import { requireToolContext } from "./helpers";
import type { ChatToolDeps } from "./types";

const resolveDecisionInputSchema = z.object({
  question: z.string().min(1).describe("The decision question"),
  options: z.array(z.string().min(1)).optional().describe("Known options being considered"),
  context: z
    .object({
      project: z.string().optional(),
      feature: z.string().optional(),
    })
    .optional()
    .describe("Optional project/feature scope for searching decisions"),
});

export function createResolveDecisionTool(deps: ChatToolDeps) {
  return tool({
    description:
      "Infer an answer to a decision question from graph context. Returns resolved/inferred/unresolved with rationale and sources.",
    inputSchema: resolveDecisionInputSchema,
    execute: async (input, options) => {
      const context = requireToolContext(options);
      const queryEmbedding = await createEmbeddingVector(deps.embeddingModel, input.question, deps.embeddingDimension);
      if (!queryEmbedding) {
        throw new Error("failed to create query embedding for resolve_decision");
      }

      const projectRecord = input.context?.project
        ? await resolveWorkspaceProjectRecord({
            surreal: deps.surreal,
            workspaceRecord: context.workspaceRecord,
            projectInput: input.context.project,
          })
        : undefined;

      const featureRecord = input.context?.feature
        ? await resolveWorkspaceFeatureRecord({
            surreal: deps.surreal,
            workspaceRecord: context.workspaceRecord,
            featureInput: input.context.feature,
          })
        : undefined;

      const candidates = await listDecisionConstraintCandidates({
        surreal: deps.surreal,
        workspaceRecord: context.workspaceRecord,
        queryEmbedding,
        ...(projectRecord ? { projectRecord } : {}),
        limit: 10,
      });

      const decisionCandidates = candidates.filter((candidate) => candidate.kind === "decision");
      const topDecision = decisionCandidates[0];

      if (topDecision && topDecision.score >= 0.92) {
        const existingDecision = parseRecordIdString(topDecision.id, ["decision"], "decision");
        const resolvedFrom = await getDecisionPrimarySourceMessage({
          surreal: deps.surreal,
          workspaceRecord: context.workspaceRecord,
          decisionRecord: existingDecision,
        });

        await createExtractionProvenanceEdge({
          surreal: deps.surreal,
          sourceRecord: context.currentMessageRecord,
          targetRecord: existingDecision,
          now: new Date(),
          confidence: Math.max(topDecision.score, 0.6),
          model: deps.extractionModelId,
          fromText: input.question,
          evidence: context.latestUserText,
          evidenceSourceRecord: context.currentMessageRecord,
          ...(resolvedFrom ? { resolvedFromRecord: resolvedFrom } : {}),
        });

        return {
          status: "resolved",
          decision: {
            id: `decision:${topDecision.id}`,
            name: topDecision.name,
          },
          confidence: Number(topDecision.score.toFixed(4)),
          sources: [
            {
              id: `decision:${topDecision.id}`,
              name: topDecision.name,
              score: Number(topDecision.score.toFixed(4)),
            },
          ],
        };
      }

      if (topDecision && topDecision.score >= 0.78) {
        const now = new Date();
        const sources = candidates.slice(0, 5);
        const basedOn = sources
          .map((source) => {
            try {
              return parseRecordIdString(source.id, [source.kind as "project" | "feature" | "task" | "decision" | "question"], source.kind as any);
            } catch {
              return undefined;
            }
          })
          .filter((value): value is GraphEntityRecord => value !== undefined);

        const decisionRecord = await createDecisionRecord({
          surreal: deps.surreal,
          summary: input.question,
          status: "inferred",
          now,
          sourceMessageRecord: context.currentMessageRecord,
          rationale: `Inferred from existing graph context with ${sources.length} related entities.`,
          ...(input.options && input.options.length > 0 ? { optionsConsidered: input.options } : {}),
          ...(basedOn.length > 0 ? { basedOn } : {}),
          inferredBy: "chat_agent",
          decidedByName: "chat_agent",
          ...(projectRecord ? { projectRecord } : {}),
          ...(featureRecord ? { featureRecord } : {}),
        });

        await createExtractionProvenanceEdge({
          surreal: deps.surreal,
          sourceRecord: context.currentMessageRecord,
          targetRecord: decisionRecord,
          now,
          confidence: Math.max(topDecision.score, 0.6),
          model: deps.extractionModelId,
          fromText: input.question,
          evidence: context.latestUserText,
          evidenceSourceRecord: context.currentMessageRecord,
        });

        return {
          status: "inferred",
          decision: {
            id: `decision:${decisionRecord.id as string}`,
            name: input.question,
          },
          confidence: Number(topDecision.score.toFixed(4)),
          rationale: `Top matching decision: ${topDecision.name}. Related context was strong enough to infer a recommendation.`,
          sources: sources.map((source) => ({
            id: `${source.kind}:${source.id}`,
            name: source.name,
            score: Number(source.score.toFixed(4)),
          })),
        };
      }

      return {
        status: "unresolved",
        relatedContext: candidates.slice(0, 6).map((source) => ({
          id: `${source.kind}:${source.id}`,
          kind: source.kind,
          name: source.name,
          score: Number(source.score.toFixed(4)),
        })),
        suggestProvisional: true,
      };
    },
  });
}

