import { RecordId, type Surreal } from "surrealdb";
import { logInfo, logWarning } from "../http/observability";

type BackfillRow = {
  id: RecordId<"task" | "decision" | "question", string>;
  source_message?: RecordId<"message", string>;
  source_commit?: RecordId<"git_commit", string>;
};

export async function backfillEntityWorkspaces(surreal: Surreal): Promise<void> {
  const tables = ["task", "decision", "question"] as const;
  let totalBackfilled = 0;
  let totalUnresolved = 0;

  for (const table of tables) {
    const textField = table === "task" ? "title" : table === "decision" ? "summary" : "text";
    const [rows] = await surreal
      .query<[BackfillRow[]]>(
        `SELECT id, source_message, source_commit FROM ${table} WHERE workspace = NONE;`,
      )
      .collect<[BackfillRow[]]>();

    if (rows.length === 0) continue;

    let backfilled = 0;
    let unresolved = 0;

    for (const row of rows) {
      let workspace: RecordId<"workspace", string> | undefined;

      // Path 1: source_message → message.conversation → conversation.workspace
      if (!workspace && row.source_message) {
        const [msgRows] = await surreal
          .query<[Array<{ workspace: RecordId<"workspace", string> }>]>(
            [
              "SELECT workspace FROM conversation",
              "WHERE id IN (SELECT VALUE conversation FROM message WHERE id = $message)",
              "LIMIT 1;",
            ].join(" "),
            { message: row.source_message },
          )
          .collect<[Array<{ workspace: RecordId<"workspace", string> }>]>();

        if (msgRows[0]?.workspace) {
          workspace = msgRows[0].workspace;
        }
      }

      // Path 2: source_commit → git_commit.workspace
      if (!workspace && row.source_commit) {
        const [commitRows] = await surreal
          .query<[Array<{ workspace: RecordId<"workspace", string> }>]>(
            "SELECT workspace FROM git_commit WHERE id = $commit LIMIT 1;",
            { commit: row.source_commit },
          )
          .collect<[Array<{ workspace: RecordId<"workspace", string> }>]>();

        if (commitRows[0]?.workspace) {
          workspace = commitRows[0].workspace;
        }
      }

      // Path 3: belongs_to → project → has_project.in (workspace)
      if (!workspace) {
        const [projectRows] = await surreal
          .query<[Array<{ in: RecordId<"workspace", string> }>]>(
            [
              "SELECT `in` FROM has_project",
              "WHERE out IN (SELECT VALUE out FROM belongs_to WHERE `in` = $entity)",
              "LIMIT 1;",
            ].join(" "),
            { entity: row.id },
          )
          .collect<[Array<{ in: RecordId<"workspace", string> }>]>();

        if (projectRows[0]?.in) {
          workspace = projectRows[0].in;
        }
      }

      if (workspace) {
        await surreal.update(row.id).merge({ workspace });
        backfilled++;
      } else {
        unresolved++;
      }
    }

    if (backfilled > 0) {
      logInfo("backfill.workspace.completed", `Backfilled workspace for ${backfilled} ${table} records`, {
        table,
        backfilled,
        unresolved,
      });
    }

    if (unresolved > 0) {
      logWarning("backfill.workspace.unresolved", `Could not resolve workspace for ${unresolved} ${table} records`, {
        table,
        unresolved,
      });
    }

    totalBackfilled += backfilled;
    totalUnresolved += unresolved;
  }

  if (totalBackfilled > 0 || totalUnresolved > 0) {
    logInfo("backfill.workspace.summary", `Workspace backfill: ${totalBackfilled} resolved, ${totalUnresolved} unresolved`, {
      totalBackfilled,
      totalUnresolved,
    });
  }
}

