  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import { isRicherEntityName } from "./dedup";
  4→import { isFuzzyNameMatch, normalizeName } from "./normalize";
  5→import type { ExtractionPromptEntity } from "./schema";
  6→import type {
  7→  CandidateEntityRow,
  8→  ExtractableEntityKind,
  9→  GraphEntityRecord,
 10→  PersistableExtractableEntityKind,
 11→  ProjectScopeRow,
 12→  SourceRecord,
 13→} from "./types";
 14→import { ensureProjectFeatureEdge, ensureWorkspaceProjectEdge, resolveEntityProject } from "../workspace/workspace-scope";
 15→import { createEmbedding } from "./embedding-writeback";
 16→
 17→export async function upsertGraphEntity(input: {
 18→  surreal: Surreal;
 19→  embeddingModel: any;
 20→  embeddingDimension: number;
 21→  extractionModelId: string;
 22→  workspaceRecord: RecordId<"workspace", string>;
 23→  workspaceProjects: ProjectScopeRow[];
 24→  sourceRecord: SourceRecord;
 25→  sourceKind: "message" | "document_chunk" | "git_commit";
 26→  promptText: string;
 27→  extracted: ExtractionPromptEntity & { kind: PersistableExtractableEntityKind };
 28→  sourceMessageRecord?: RecordId<"message", string>;
 29→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 30→  sourceCommitRecord?: RecordId<"git_commit", string>;
 31→  resolvedFromMessageRecord?: RecordId<"message", string>;
 32→  now: Date;
 33→}): Promise<{ record: GraphEntityRecord; text: string; kind: PersistableExtractableEntityKind; created: boolean }> {
 34→  const candidateEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.extracted.text);
 35→  const candidates = await loadWorkspaceKindCandidates(input.surreal, input.workspaceRecord, input.extracted.kind);
 36→  const normalizedExtractedText = normalizeName(input.extracted.text);
 37→
 38→  const exactNameCandidate = candidates.find((candidate) => normalizeName(candidate.text) === normalizedExtractedText);
 39→  if (exactNameCandidate) {
 40→    const mergedText = await maybeUpgradeMergedEntityName(
 41→      input.surreal,
 42→      input.extracted.kind,
 43→      input.extracted.text,
 44→      exactNameCandidate,
 45→      input.now,
 46→    );
 47→
 48→    await createProvenanceEdge({
 49→      surreal: input.surreal,
 50→      sourceRecord: input.sourceRecord,
 51→      targetRecord: exactNameCandidate.id,
 52→      confidence: input.extracted.confidence,
 53→      model: input.extractionModelId,
 54→      now: input.now,
 55→      fromText: input.extracted.text,
 56→      evidence: input.extracted.evidence,
 57→      evidenceSourceRecord: input.sourceMessageRecord,
 58→      resolvedFromRecord: input.resolvedFromMessageRecord,
 59→    });
 60→
 61→    return {
 62→      record: exactNameCandidate.id,
 63→      text: mergedText,
 64→      kind: input.extracted.kind,
 65→      created: false,
 66→    };
 67→  }
 68→
 69→  let bestCandidate: CandidateEntityRow | undefined;
 70→  let bestSimilarity = -1;
 71→
 72→  for (const candidate of candidates) {
 73→    if (!candidate.embedding || !candidateEmbedding) {
 74→      continue;
 75→    }
 76→
 77→    const similarity = cosineSimilarity(candidateEmbedding, candidate.embedding);
 78→    if (similarity > bestSimilarity) {
 79→      bestSimilarity = similarity;
 80→      bestCandidate = candidate;
 81→    }
 82→  }
 83→
 84→  const fuzzyMatch = bestCandidate
 85→    ? isFuzzyNameMatch(normalizeName(input.extracted.text), normalizeName(bestCandidate.text))
 86→    : false;
 87→
 88→  if (bestCandidate && bestSimilarity > 0.95 && fuzzyMatch) {
 89→    const mergedText = await maybeUpgradeMergedEntityName(
 90→      input.surreal,
 91→      input.extracted.kind,
 92→      input.extracted.text,
 93→      bestCandidate,
 94→      input.now,
 95→    );
 96→
 97→    await createProvenanceEdge({
 98→      surreal: input.surreal,
 99→      sourceRecord: input.sourceRecord,
100→      targetRecord: bestCandidate.id,
101→      confidence: input.extracted.confidence,
102→      model: input.extractionModelId,
103→      now: input.now,
104→      fromText: input.extracted.text,
105→      evidence: input.extracted.evidence,
106→      evidenceSourceRecord: input.sourceMessageRecord,
107→      resolvedFromRecord: input.resolvedFromMessageRecord,
108→    });
109→
110→    return {
111→      record: bestCandidate.id,
112→      text: mergedText,
113→      kind: input.extracted.kind,
114→      created: false,
115→    };
116→  }
117→
118→  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
119→  await input.surreal.create(entityRecord).content(
120→    buildEntityRecordContent(
121→      input.extracted.kind,
122→      input.extracted.text,
123→      input.extracted.confidence,
124→      input.now,
125→      candidateEmbedding,
126→      input.sourceMessageRecord,
127→      input.sourceCommitRecord,
128→      input.extracted.category,
129→      input.extracted.priority,
130→    ),
131→  );
132→
133→  await createProvenanceEdge({
134→    surreal: input.surreal,
135→    sourceRecord: input.sourceRecord,
136→    targetRecord: entityRecord,
137→    confidence: input.extracted.confidence,
138→    model: input.extractionModelId,
139→    now: input.now,
140→    fromText: input.extracted.text,
141→    evidence: input.extracted.evidence,
142→    evidenceSourceRecord: input.sourceMessageRecord,
143→    resolvedFromRecord: input.resolvedFromMessageRecord,
144→  });
145→
146→  if (input.extracted.kind === "project") {
147→    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
148→    input.workspaceProjects.push({
149→      id: entityRecord as RecordId<"project", string>,
150→      name: input.extracted.text,
151→    });
152→  }
153→
154→  if (input.extracted.kind === "feature") {
155→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
156→    if (projectRecord) {
157→      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
158→    }
159→  }
160→
161→  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
162→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
163→    if (projectRecord) {
164→      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
165→        added_at: input.now,
166→      }).output("after");
167→    }
168→  }
169→
170→  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
171→    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
172→      kind: "POSSIBLE_DUPLICATE",
173→      confidence: bestSimilarity,
174→      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
175→      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
176→      ...(input.sourceCommitRecord ? { source_commit: input.sourceCommitRecord } : {}),
177→      extracted_at: input.now,
178→      created_at: input.now,
179→      from_text: input.extracted.text,
180→      to_text: bestCandidate.text,
181→    }).output("after");
182→  }
183→
184→  return {
185→    record: entityRecord,
186→    text: input.extracted.text,
187→    kind: input.extracted.kind,
188→    created: true,
189→  };
190→}
