192→export async function maybeUpgradeMergedEntityName(
193→  surreal: Surreal,
194→  kind: PersistableExtractableEntityKind,
195→  incomingText: string,
196→  candidate: CandidateEntityRow,
197→  now: Date,
198→): Promise<string> {
199→  if (!isRicherEntityName(incomingText, candidate.text)) {
200→    return candidate.text;
201→  }
202→
203→  if (kind === "project" || kind === "feature") {
204→    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
205→      name: incomingText,
206→      updated_at: now,
207→    });
208→    return incomingText;
209→  }
210→
211→  if (kind === "task") {
212→    await surreal.update(candidate.id as RecordId<"task", string>).merge({
213→      title: incomingText,
214→      updated_at: now,
215→    });
216→    return incomingText;
217→  }
218→
219→  if (kind === "decision") {
220→    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
221→      summary: incomingText,
222→      updated_at: now,
223→    });
224→    return incomingText;
225→  }
226→
227→  await surreal.update(candidate.id as RecordId<"question", string>).merge({
228→    text: incomingText,
229→    updated_at: now,
230→  });
231→
232→  return incomingText;
233→}
