259→function buildEntityRecordContent(
260→  kind: PersistableExtractableEntityKind,
261→  text: string,
262→  confidence: number,
263→  now: Date,
264→  embedding?: number[],
265→  sourceMessageRecord?: RecordId<"message", string>,
266→  sourceCommitRecord?: RecordId<"git_commit", string>,
267→  category?: string,
268→  priority?: string,
269→): Record<string, unknown> {
270→  if (kind === "project") {
271→    return {
272→      name: text,
273→      status: "active",
274→      ...(embedding ? { embedding } : {}),
275→      created_at: now,
276→      updated_at: now,
277→    };
278→  }
279→
280→  if (kind === "feature") {
281→    return {
282→      name: text,
283→      status: "active",
284→      ...(embedding ? { embedding } : {}),
285→      created_at: now,
286→      updated_at: now,
287→    };
288→  }
289→
290→  if (kind === "task") {
291→    return {
292→      title: text,
293→      status: "open",
294→      extraction_confidence: confidence,
295→      extracted_at: now,
296→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
297→      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
298→      ...(embedding ? { embedding } : {}),
299→      ...(category ? { category } : {}),
300→      ...(priority ? { priority } : {}),
301→      created_at: now,
302→      updated_at: now,
303→    };
304→  }
305→
306→  if (kind === "decision") {
307→    return {
308→      summary: text,
309→      status: "extracted",
310→      extraction_confidence: confidence,
311→      extracted_at: now,
312→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
313→      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
314→      ...(embedding ? { embedding } : {}),
315→      ...(category ? { category } : {}),
316→      ...(priority ? { priority } : {}),
317→      created_at: now,
318→      updated_at: now,
319→    };
320→  }
321→
322→  // question (fallthrough)
323→  return {
324→    text,
325→    status: "open",
326→    extraction_confidence: confidence,
327→    extracted_at: now,
328→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
329→    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
330→    ...(embedding ? { embedding } : {}),
331→    ...(category ? { category } : {}),
332→    ...(priority ? { priority } : {}),
333→    created_at: now,
334→    updated_at: now,
335→  };
336→}
