452→function uniqueCandidateRows(rows: CandidateEntityRow[]): CandidateEntityRow[] {
453→  const byId = new Map<string, CandidateEntityRow>();
454→  for (const row of rows) {
455→    byId.set(row.id.id as string, row);
456→  }
457→  return [...byId.values()];
458→}
459→
460→export async function appendWorkspaceTools(
461→  surreal: Surreal,
462→  workspaceRecord: RecordId<"workspace", string>,
463→  toolsToAdd: string[],
464→  now: Date,
465→): Promise<void> {
466→  const [rows] = await surreal
467→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
468→      workspace: workspaceRecord,
469→    })
470→    .collect<[Array<{ tools?: string[] }>]>();
471→
472→  const existingTools = rows[0]?.tools ?? [];
473→  const merged = [...new Set([...existingTools, ...toolsToAdd])];
474→  await surreal.update(workspaceRecord).merge({
475→    tools: merged,
476→    updated_at: now,
477→  });
478→}
479→
480→export function normalizeRelationshipKind(value: string): string {
481→  return value
482→    .trim()
483→    .replace(/[^a-zA-Z0-9]+/g, "_")
484→    .replace(/_+/g, "_")
485→    .replace(/^_/, "")
486→    .replace(/_$/, "")
487→    .toUpperCase();
488→}
489→
490→function cosineSimilarity(a: number[], b: number[]): number {
491→  if (a.length !== b.length) {
492→    return -1;
493→  }
494→
495→  let dot = 0;
496→  let normA = 0;
497→  let normB = 0;
498→
499→  for (let i = 0; i < a.length; i += 1) {
500→    dot += a[i] * b[i];
501→    normA += a[i] * a[i];
502→    normB += b[i] * b[i];
503→  }
504→
505→  if (normA === 0 || normB === 0) {
506→    return -1;
507→  }
508→
509→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
510→}
