import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import { isRicherEntityName } from "./dedup";
import { isFuzzyNameMatch, normalizeName } from "./normalize";
import type { ExtractionPromptEntity } from "./schema";
import type {
  CandidateEntityRow,
  ExtractableEntityKind,
  GraphEntityRecord,
  PersistableExtractableEntityKind,
  ProjectScopeRow,
  SourceRecord,
} from "./types";
import { ensureProjectFeatureEdge, ensureWorkspaceProjectEdge, resolveEntityProject } from "../workspace/workspace-scope";
import { createEmbedding } from "./embedding-writeback";

export async function upsertGraphEntity(input: {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  extractionModelId: string;
  workspaceRecord: RecordId<"workspace", string>;
  workspaceProjects: ProjectScopeRow[];
  sourceRecord: SourceRecord;
  sourceKind: "message" | "document_chunk" | "git_commit";
  promptText: string;
  extracted: ExtractionPromptEntity & { kind: PersistableExtractableEntityKind };
  sourceMessageRecord?: RecordId<"message", string>;
  sourceChunkRecord?: RecordId<"document_chunk", string>;
  sourceCommitRecord?: RecordId<"git_commit", string>;
  resolvedFromMessageRecord?: RecordId<"message", string>;
  now: Date;
}): Promise<{ record: GraphEntityRecord; text: string; kind: PersistableExtractableEntityKind; created: boolean }> {
  const candidateEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.extracted.text);
  const candidates = await loadWorkspaceKindCandidates(input.surreal, input.workspaceRecord, input.extracted.kind);
  const normalizedExtractedText = normalizeName(input.extracted.text);

  const exactNameCandidate = candidates.find((candidate) => normalizeName(candidate.text) === normalizedExtractedText);
  if (exactNameCandidate) {
    const mergedText = await maybeUpgradeMergedEntityName(
      input.surreal,
      input.extracted.kind,
      input.extracted.text,
      exactNameCandidate,
      input.now,
    );

    await createProvenanceEdge({
      surreal: input.surreal,
      sourceRecord: input.sourceRecord,
      targetRecord: exactNameCandidate.id,
      confidence: input.extracted.confidence,
      model: input.extractionModelId,
      now: input.now,
      fromText: input.extracted.text,
      evidence: input.extracted.evidence,
      evidenceSourceRecord: input.sourceMessageRecord,
      resolvedFromRecord: input.resolvedFromMessageRecord,
    });

    return {
      record: exactNameCandidate.id,
      text: mergedText,
      kind: input.extracted.kind,
      created: false,
    };
  }

  let bestCandidate: CandidateEntityRow | undefined;
  let bestSimilarity = -1;

  for (const candidate of candidates) {
    if (!candidate.embedding || !candidateEmbedding) {
      continue;
    }

    const similarity = cosineSimilarity(candidateEmbedding, candidate.embedding);
    if (similarity > bestSimilarity) {
      bestSimilarity = similarity;
      bestCandidate = candidate;
    }
  }

  const fuzzyMatch = bestCandidate
    ? isFuzzyNameMatch(normalizeName(input.extracted.text), normalizeName(bestCandidate.text))
    : false;

  if (bestCandidate && bestSimilarity > 0.95 && fuzzyMatch) {
    const mergedText = await maybeUpgradeMergedEntityName(
      input.surreal,
      input.extracted.kind,
      input.extracted.text,
      bestCandidate,
      input.now,
    );

    await createProvenanceEdge({
      surreal: input.surreal,
      sourceRecord: input.sourceRecord,
      targetRecord: bestCandidate.id,
      confidence: input.extracted.confidence,
      model: input.extractionModelId,
      now: input.now,
      fromText: input.extracted.text,
      evidence: input.extracted.evidence,
      evidenceSourceRecord: input.sourceMessageRecord,
      resolvedFromRecord: input.resolvedFromMessageRecord,
    });

    return {
      record: bestCandidate.id,
      text: mergedText,
      kind: input.extracted.kind,
      created: false,
    };
  }

  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
  await input.surreal.create(entityRecord).content(
    buildEntityRecordContent(
      input.extracted.kind,
      input.extracted.text,
      input.extracted.confidence,
      input.now,
      candidateEmbedding,
      input.sourceMessageRecord,
      input.sourceCommitRecord,
      input.extracted.category,
      input.extracted.priority,
      input.workspaceRecord,
    ),
  );

  await createProvenanceEdge({
    surreal: input.surreal,
    sourceRecord: input.sourceRecord,
    targetRecord: entityRecord,
    confidence: input.extracted.confidence,
    model: input.extractionModelId,
    now: input.now,
    fromText: input.extracted.text,
    evidence: input.extracted.evidence,
    evidenceSourceRecord: input.sourceMessageRecord,
    resolvedFromRecord: input.resolvedFromMessageRecord,
  });

  if (input.extracted.kind === "project") {
    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
    input.workspaceProjects.push({
      id: entityRecord as RecordId<"project", string>,
      name: input.extracted.text,
    });
  }

  if (input.extracted.kind === "feature") {
    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
    if (projectRecord) {
      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
    }
  }

  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
    if (projectRecord) {
      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
        added_at: input.now,
      }).output("after");
    }
  }

  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
      kind: "POSSIBLE_DUPLICATE",
      confidence: bestSimilarity,
      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
      ...(input.sourceCommitRecord ? { source_commit: input.sourceCommitRecord } : {}),
      extracted_at: input.now,
      created_at: input.now,
      from_text: input.extracted.text,
      to_text: bestCandidate.text,
    }).output("after");
  }

  return {
    record: entityRecord,
    text: input.extracted.text,
    kind: input.extracted.kind,
    created: true,
  };
}

export async function maybeUpgradeMergedEntityName(
  surreal: Surreal,
  kind: PersistableExtractableEntityKind,
  incomingText: string,
  candidate: CandidateEntityRow,
  now: Date,
): Promise<string> {
  if (!isRicherEntityName(incomingText, candidate.text)) {
    return candidate.text;
  }

  if (kind === "project" || kind === "feature") {
    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
      name: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  if (kind === "task") {
    await surreal.update(candidate.id as RecordId<"task", string>).merge({
      title: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  if (kind === "decision") {
    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
      summary: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  await surreal.update(candidate.id as RecordId<"question", string>).merge({
    text: incomingText,
    updated_at: now,
  });

  return incomingText;
}

export async function createProvenanceEdge(input: {
  surreal: Surreal;
  sourceRecord: SourceRecord;
  targetRecord: GraphEntityRecord;
  confidence: number;
  model: string;
  now: Date;
  fromText: string;
  evidence: string;
  evidenceSourceRecord?: RecordId<"message", string>;
  resolvedFromRecord?: RecordId<"message", string>;
}): Promise<void> {
  await input.surreal.relate(input.sourceRecord, new RecordId("extraction_relation", randomUUID()), input.targetRecord, {
    confidence: input.confidence,
    extracted_at: input.now,
    created_at: input.now,
    model: input.model,
    from_text: input.fromText,
    evidence: input.evidence,
    ...(input.evidenceSourceRecord ? { evidence_source: input.evidenceSourceRecord } : {}),
    ...(input.resolvedFromRecord ? { resolved_from: input.resolvedFromRecord } : {}),
  }).output("after");
}

function buildEntityRecordContent(
  kind: PersistableExtractableEntityKind,
  text: string,
  confidence: number,
  now: Date,
  embedding?: number[],
  sourceMessageRecord?: RecordId<"message", string>,
  sourceCommitRecord?: RecordId<"git_commit", string>,
  category?: string,
  priority?: string,
  workspaceRecord?: RecordId<"workspace", string>,
): Record<string, unknown> {
  if (kind === "project") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "feature") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "task") {
    return {
      title: text,
      status: "open",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "decision") {
    return {
      summary: text,
      status: "extracted",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  // question (fallthrough)
  return {
    text,
    status: "open",
    extraction_confidence: confidence,
    extracted_at: now,
    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
    ...(embedding ? { embedding } : {}),
    ...(category ? { category } : {}),
    ...(priority ? { priority } : {}),
    ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
    created_at: now,
    updated_at: now,
  };
}

export async function loadWorkspaceKindCandidates(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  kind: ExtractableEntityKind,
): Promise<CandidateEntityRow[]> {
  if (kind === "project") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "person") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "feature") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        [
          "SELECT id, name AS text, embedding",
          "FROM feature",
          "WHERE id IN (",
          "  SELECT VALUE out",
          "  FROM has_feature",
          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
          ");",
        ].join(" "),
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "task") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, title AS text, embedding FROM task WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "decision") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, summary AS text, embedding FROM decision WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  const [rows] = await surreal
    .query<[CandidateEntityRow[]]>(
      "SELECT id, text AS text, embedding FROM question WHERE workspace = $workspace;",
      { workspace: workspaceRecord },
    )
    .collect<[CandidateEntityRow[]]>();
  return rows;
}

export async function appendWorkspaceTools(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  toolsToAdd: string[],
  now: Date,
): Promise<void> {
  const [rows] = await surreal
    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
      workspace: workspaceRecord,
    })
    .collect<[Array<{ tools?: string[] }>]>();

  const existingTools = rows[0]?.tools ?? [];
  const merged = [...new Set([...existingTools, ...toolsToAdd])];
  await surreal.update(workspaceRecord).merge({
    tools: merged,
    updated_at: now,
  });
}

export function normalizeRelationshipKind(value: string): string {
  return value
    .trim()
    .replace(/[^a-zA-Z0-9]+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_/, "")
    .replace(/_$/, "")
    .toUpperCase();
}

function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) {
    return -1;
  }

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i += 1) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  if (normA === 0 || normB === 0) {
    return -1;
  }

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

import { randomUUID } from "node:crypto";
import { RecordId, Surreal } from "surrealdb";
import { cosineSimilarity } from "./embeddings";

export type GraphEntityTable = "workspace" | "project" | "person" | "feature" | "task" | "decision" | "question";

export type GraphEntityRecord = RecordId<GraphEntityTable, string>;

export type SearchEntityKind = "project" | "feature" | "task" | "decision" | "question";

export type ConversationEntity = {
  id: string;
  kind: GraphEntityTable;
  name: string;
  confidence: number;
  sourceMessageId?: string;
};

export type WorkspaceProjectSummary = {
  id: string;
  name: string;
  activeTaskCount: number;
};

export type WorkspaceDecisionSummary = {
  id: string;
  name: string;
  status: string;
  priority?: string;
  project?: string;
};

export type WorkspaceQuestionSummary = {
  id: string;
  name: string;
  priority?: string;
  project?: string;
};

export type RankedEntity = {
  id: string;
  kind: SearchEntityKind;
  name: string;
  score: number;
  status?: string;
  project?: string;
};

export type EntityNeighbor = {
  id: string;
  kind: GraphEntityTable;
  name: string;
  relationKind: string;
  direction: "incoming" | "outgoing";
  confidence: number;
};

export type EntityProvenance = {
  sourceId: string;
  sourceKind: "message" | "document_chunk" | "git_commit";
  confidence: number;
  extractedAt: string;
  evidence?: string;
  evidenceSource?: string;
  resolvedFrom?: string;
  fromText?: string;
};

export type EntityDetail = {
  entity: {
    id: string;
    kind: GraphEntityTable;
    name: string;
    data: Record<string, unknown>;
  };
  relationships: EntityNeighbor[];
  provenance: EntityProvenance[];
};

export type ProjectStatus = {
  project: {
    id: string;
    name: string;
  };
  tasks: {
    active: number;
    completed: number;
    blocked: number;
    recent: Array<{ id: string; name: string; status: string; priority?: string }>;
  };
  decisions: Array<{ id: string; name: string; status: string; priority?: string }>;
  questions: Array<{ id: string; name: string; status: string; priority?: string }>;
  features: Array<{ id: string; name: string; status: string }>;
};

export type RankedMessage = {
  id: string;
  conversationId: string;
  text: string;
  score: number;
  createdAt: string;
};

export type GraphViewRawEntity = {
  id: string;
  kind: GraphEntityTable;
  name: string;
};

export type GraphViewRawEdge = {
  id: string;
  kind: string;
  fromId: string;
  toId: string;
  confidence: number;
};

export type GraphViewRawResult = {
  entities: GraphViewRawEntity[];
  edges: GraphViewRawEdge[];
};

type EntitySearchCandidate = {
  id: GraphEntityRecord;
  kind: SearchEntityKind;
  name: string;
  status?: string;
  embedding?: number[];
};

const SEARCH_KINDS: SearchEntityKind[] = ["project", "feature", "task", "decision", "question"];

function toRecordIdString(record: RecordId<string, string>): string {
  return record.id as string;
}

function toIsoString(value: string | Date): string {
  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
}

function normalizeSearchValue(value: string): string {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ");
}

export function parseRecordIdString<T extends string>(
  value: string,
  allowedTables: T[],
  fallbackTable?: T,
): RecordId<T, string> {
  const normalized = value.trim();
  if (normalized.length === 0) {
    throw new Error("record id is required");
  }

  const separatorIndex = normalized.indexOf(":");
  if (separatorIndex === -1) {
    if (!fallbackTable) {
      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
    }

    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
  }

  const table = normalized.slice(0, separatorIndex) as T;
  const id = normalized.slice(separatorIndex + 1);
  if (!allowedTables.includes(table)) {
    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
  }

  if (id.length === 0) {
    throw new Error("record id is missing its identifier component");
  }

  return new RecordId(table, id) as RecordId<T, string>;
}

export async function readEntityName(
  surreal: Surreal,
  record: GraphEntityRecord,
): Promise<string | undefined> {
  const table = record.table.name;

  if (table === "workspace" || table === "project" || table === "person" || table === "feature") {
    const row = await surreal.select<{ name: string }>(record as RecordId<typeof table, string>);
    return row?.name;
  }

  if (table === "task") {
    const row = await surreal.select<{ title: string }>(record as RecordId<"task", string>);
    return row?.title;
  }

  if (table === "decision") {
    const row = await surreal.select<{ summary: string }>(record as RecordId<"decision", string>);
    return row?.summary;
  }

  const row = await surreal.select<{ text: string }>(record as RecordId<"question", string>);
  return row?.text;
}

async function getWorkspaceProjectRows(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<Array<{ id: RecordId<"project", string>; name: string }>> {
  const [rows] = await surreal
    .query<[Array<{ id: RecordId<"project", string>; name: string }>]>(
      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
      { workspace: workspaceRecord },
    )
    .collect<[Array<{ id: RecordId<"project", string>; name: string }>]>();

  return rows;
}

async function getWorkspaceMessageIds(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<RecordId<"message", string>[]> {
  const [rows] = await surreal
    .query<[Array<RecordId<"message", string>>]>(
      "SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace);",
      { workspace: workspaceRecord },
    )
    .collect<[Array<RecordId<"message", string>>]>();

  return rows;
}

export async function isEntityInWorkspace(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  entityRecord: GraphEntityRecord,
): Promise<boolean> {
  const table = entityRecord.table.name;

  if (table === "workspace") {
    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
  }

  if (table === "project") {
    const [rows] = await surreal
      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
        { workspace: workspaceRecord, project: entityRecord },
      )
      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();

    return rows.length > 0;
  }

  if (table === "person") {
    const [rows] = await surreal
      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
        { workspace: workspaceRecord, person: entityRecord },
      )
      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();

    return rows.length > 0;
  }

  if (table === "feature") {
    const [rows] = await surreal
      .query<[Array<{ id: RecordId<"feature", string> }>]>(
        [
          "SELECT id",
          "FROM feature",
          "WHERE id = $feature",
          "AND id IN (",
          "  SELECT VALUE out",
          "  FROM has_feature",
          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
          ");",
        ].join(" "),
        { workspace: workspaceRecord, feature: entityRecord },
      )
      .collect<[Array<{ id: RecordId<"feature", string> }>]>();

    return rows.length > 0;
  }

  if (table === "task" || table === "decision" || table === "question") {
    const [rows] = await surreal
      .query<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>(
        `SELECT id FROM ${table} WHERE id = $entity AND workspace = $workspace;`,
        { workspace: workspaceRecord, entity: entityRecord },
      )
      .collect<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>();

    return rows.length > 0;
  }

  return false;
}

export async function listConversationEntities(input: {
  surreal: Surreal;
  conversationRecord: RecordId<"conversation", string>;
  workspaceRecord: RecordId<"workspace", string>;
  limit: number;
  inheritedEntityIds?: RecordId[];
}): Promise<ConversationEntity[]> {
  const [rows] = await input.surreal
    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
      [
        "SELECT `in`, out, confidence, extracted_at",
        "FROM extraction_relation",
        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
        "ORDER BY extracted_at DESC",
        "LIMIT $limit;",
      ].join(" "),
      {
        conversation: input.conversationRecord,
        limit: input.limit,
      },
    )
    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;

  const items: ConversationEntity[] = [];
  const seen = new Set<string>();

  for (const row of rows) {
    const table = row.out.table.name as GraphEntityTable;
    if (
      table !== "workspace" &&
      table !== "project" &&
      table !== "person" &&
      table !== "feature" &&
      table !== "task" &&
      table !== "decision" &&
      table !== "question"
    ) {
      continue;
    }

    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
    if (!scoped) {
      continue;
    }

    const entityKey = `${table}:${toRecordIdString(row.out)}`;
    if (seen.has(entityKey)) {
      continue;
    }

    const name = await readEntityName(input.surreal, row.out);
    if (!name) {
      continue;
    }

    items.push({
      id: toRecordIdString(row.out),
      kind: table,
      name,
      confidence: row.confidence,
      sourceMessageId: toRecordIdString(row.in),
    });
    seen.add(entityKey);
  }

  // Merge inherited entities from parent conversation when branch has sparse context
  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
    const [inheritedRows] = await input.surreal
      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
        [
          "SELECT `in`, out, confidence, extracted_at",
          "FROM extraction_relation",
          "WHERE out IN $entityIds",
          "ORDER BY extracted_at DESC",
          "LIMIT $limit;",
        ].join(" "),
        { entityIds: input.inheritedEntityIds, limit: input.limit },
      )
      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();

    for (const row of inheritedRows) {
      const table = row.out.table.name as GraphEntityTable;
      if (
        table !== "workspace" &&
        table !== "project" &&
        table !== "person" &&
        table !== "feature" &&
        table !== "task" &&
        table !== "decision" &&
        table !== "question"
      ) {
        continue;
      }

      const entityKey = `${table}:${toRecordIdString(row.out)}`;
      if (seen.has(entityKey)) continue;

      const name = await readEntityName(input.surreal, row.out);
      if (!name) continue;

      items.push({
        id: toRecordIdString(row.out),
        kind: table,
        name,
        confidence: row.confidence,
        sourceMessageId: toRecordIdString(row.in),
      });
      seen.add(entityKey);
    }
  }

  return items;
}

export async function listWorkspaceProjectSummaries(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  limit: number;
}): Promise<WorkspaceProjectSummary[]> {
  const projectRows = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
  const limited = projectRows.slice(0, input.limit);

  const counts = await Promise.all(
    limited.map(async (project) => {
      const [countRows] = await input.surreal
        .query<[Array<{ count: number }>]>(
          [
            "SELECT count() AS count",
            "FROM task",
            "WHERE status != 'done'",
            "AND (",
            "  id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
            "  OR id IN (",
            "    SELECT VALUE out",
            "    FROM has_task",
            "    WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
            "  )",
            ");",
          ].join(" "),
          { project: project.id },
        )
        .collect<[Array<{ count: number }>]>();

      return {
        id: toRecordIdString(project.id),
        name: project.name,
        activeTaskCount: countRows[0]?.count ?? 0,
      } satisfies WorkspaceProjectSummary;
    }),
  );

  return counts;
}

