type EntityRelationRow = {
  id: RecordId<"entity_relation", string>;
  in: GraphEntityRecord;
  out: GraphEntityRecord;
  kind: string;
  confidence: number;
};

async function collectEntityRelationEdges(
  surreal: Surreal,
  entityIds: RecordId<string, string>[],
): Promise<GraphViewRawEdge[]> {
  if (entityIds.length === 0) {
    return [];
  }

  const [rows] = await surreal
    .query<[EntityRelationRow[]]>(
      [
        "SELECT id, `in`, out, kind, confidence",
        "FROM entity_relation",
        "WHERE `in` IN $entityIds AND out IN $entityIds;",
      ].join(" "),
      { entityIds },
    )
    .collect<[EntityRelationRow[]]>();

  return rows.map((row) => ({
    id: toRecordIdString(row.id),
    fromId: toRecordIdString(row.in),
    toId: toRecordIdString(row.out),
    kind: row.kind,
    confidence: row.confidence,
  }));
}

async function resolveEntityNames(
  surreal: Surreal,
  records: GraphEntityRecord[],
): Promise<GraphViewRawEntity[]> {
  const entities: GraphViewRawEntity[] = [];

  for (const record of records) {
    const name = await readEntityName(surreal, record);
    if (!name) {
      continue;
    }

    entities.push({
      id: toRecordIdString(record),
      kind: record.table.name as GraphEntityTable,
      name,
    });
  }

  return entities;
}

export async function getProjectGraphView(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  projectRecord: RecordId<"project", string>;
}): Promise<GraphViewRawResult> {
  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.projectRecord);
  if (!scoped) {
    throw new Error("project is outside the current workspace scope");
  }

  const allRecords: GraphEntityRecord[] = [input.projectRecord as GraphEntityRecord];
  const seen = new Set<string>();
  seen.add(toRecordIdString(input.projectRecord));

  const addRecord = (record: GraphEntityRecord) => {
    const key = toRecordIdString(record);
    if (!seen.has(key)) {
      seen.add(key);
      allRecords.push(record);
    }
  };

  // Features via has_feature
  const [featureRows] = await input.surreal
    .query<[Array<RecordId<"feature", string>>]>(
      "SELECT VALUE out FROM has_feature WHERE `in` = $project;",
      { project: input.projectRecord },
    )
    .collect<[Array<RecordId<"feature", string>>]>();

  for (const record of featureRows) {
    addRecord(record as GraphEntityRecord);
  }

  // Tasks/decisions/questions via belongs_to WHERE out = project
  const [belongsToRows] = await input.surreal
    .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
      "SELECT VALUE `in` FROM belongs_to WHERE out = $project;",
      { project: input.projectRecord },
    )
    .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();

  for (const record of belongsToRows) {
    addRecord(record as GraphEntityRecord);
  }

  // Tasks via features' has_task + decisions/questions that belong_to features
  if (featureRows.length > 0) {
    const [featureTaskRows] = await input.surreal
      .query<[Array<RecordId<"task", string>>]>(
        "SELECT VALUE out FROM has_task WHERE `in` IN $features;",
        { features: featureRows },
      )
      .collect<[Array<RecordId<"task", string>>]>();

    for (const record of featureTaskRows) {
      addRecord(record as GraphEntityRecord);
    }

    const [featureBelongsRows] = await input.surreal
      .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
        "SELECT VALUE `in` FROM belongs_to WHERE out IN $features;",
        { features: featureRows },
      )
      .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();

    for (const record of featureBelongsRows) {
      addRecord(record as GraphEntityRecord);
    }
  }

  // Entities extracted from workspace messages (catches decisions/questions/tasks without belongs_to edges)
  const [provenanceRows] = await input.surreal
    .query<[Array<GraphEntityRecord>]>(
      [
        "SELECT VALUE out FROM extraction_relation",
        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace));",
      ].join(" "),
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<GraphEntityRecord>]>();

  for (const record of provenanceRows) {
    const table = record.table.name;
    if (table === "task" || table === "decision" || table === "question" || table === "feature" || table === "person") {
      addRecord(record as GraphEntityRecord);
    }
  }

  // Persons via member_of WHERE out = workspace
  const [personRows] = await input.surreal
    .query<[Array<RecordId<"person", string>>]>(
      "SELECT VALUE `in` FROM member_of WHERE out = $workspace;",
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<RecordId<"person", string>>]>();

  for (const record of personRows) {
    addRecord(record as GraphEntityRecord);
  }

  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

export async function getFocusedGraphView(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  centerEntityRecord: GraphEntityRecord;
  depth: number;
}): Promise<GraphViewRawResult> {
  const clampedDepth = Math.max(1, Math.min(3, input.depth));

  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
  if (!scoped) {
    throw new Error("entity is outside the current workspace scope");
  }

  const collected = new Map<string, GraphEntityRecord>();
  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);

  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];

  for (let hop = 0; hop < clampedDepth; hop++) {
    if (frontier.length === 0) {
      break;
    }

    const [rows] = await input.surreal
      .query<[EntityRelationRow[]]>(
        [
          "SELECT id, `in`, out, kind, confidence",
          "FROM entity_relation",
          "WHERE `in` IN $currentIds OR out IN $currentIds;",
        ].join(" "),
        { currentIds: frontier },
      )
      .collect<[EntityRelationRow[]]>();

    const nextFrontier: RecordId<string, string>[] = [];

    for (const row of rows) {
      for (const endpoint of [row.in, row.out]) {
        const key = toRecordIdString(endpoint);
        if (collected.has(key)) {
          continue;
        }

        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint);
        if (!inScope) {
          continue;
        }

        collected.set(key, endpoint);
        nextFrontier.push(endpoint);
      }
    }

    frontier = nextFrontier;
  }

  const allRecords = Array.from(collected.values());
  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

export async function getWorkspaceGraphOverview(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
}): Promise<GraphViewRawResult> {
  // Projects via has_project
  const [projectRows] = await input.surreal
    .query<[Array<RecordId<"project", string>>]>(
      "SELECT VALUE out FROM has_project WHERE `in` = $workspace;",
      { workspace: input.workspaceRecord },
    )
    .collect<[Array<RecordId<"project", string>>]>();

  const allRecords: GraphEntityRecord[] = [];

  for (const record of projectRows) {
    allRecords.push(record as GraphEntityRecord);
  }

  // Features via has_feature for each project
  if (projectRows.length > 0) {
    const [featureRows] = await input.surreal
      .query<[Array<RecordId<"feature", string>>]>(
        "SELECT VALUE out FROM has_feature WHERE `in` IN $projects;",
        { projects: projectRows },
      )
      .collect<[Array<RecordId<"feature", string>>]>();

    for (const record of featureRows) {
      allRecords.push(record as GraphEntityRecord);
    }
  }

  const entities = await resolveEntityNames(input.surreal, allRecords);
  const edges = await collectEntityRelationEdges(input.surreal, allRecords);

  return { entities, edges };
}

import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import { isRicherEntityName } from "./dedup";
import { isFuzzyNameMatch, normalizeName } from "./normalize";
import type { ExtractionPromptEntity } from "./schema";
import type {
  CandidateEntityRow,
  ExtractableEntityKind,
  GraphEntityRecord,
  PersistableExtractableEntityKind,
  ProjectScopeRow,
  SourceRecord,
} from "./types";
import { ensureProjectFeatureEdge, ensureWorkspaceProjectEdge, resolveEntityProject } from "../workspace/workspace-scope";
import { createEmbedding } from "./embedding-writeback";

export async function upsertGraphEntity(input: {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  extractionModelId: string;
  workspaceRecord: RecordId<"workspace", string>;
  workspaceProjects: ProjectScopeRow[];
  sourceRecord: SourceRecord;
  sourceKind: "message" | "document_chunk" | "git_commit";
  promptText: string;
  extracted: ExtractionPromptEntity & { kind: PersistableExtractableEntityKind };
  sourceMessageRecord?: RecordId<"message", string>;
  sourceChunkRecord?: RecordId<"document_chunk", string>;
  sourceCommitRecord?: RecordId<"git_commit", string>;
  resolvedFromMessageRecord?: RecordId<"message", string>;
  now: Date;
}): Promise<{ record: GraphEntityRecord; text: string; kind: PersistableExtractableEntityKind; created: boolean }> {
  const candidateEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.extracted.text);
  const candidates = await loadWorkspaceKindCandidates(input.surreal, input.workspaceRecord, input.extracted.kind);
  const normalizedExtractedText = normalizeName(input.extracted.text);

  const exactNameCandidate = candidates.find((candidate) => normalizeName(candidate.text) === normalizedExtractedText);
  if (exactNameCandidate) {
    const mergedText = await maybeUpgradeMergedEntityName(
      input.surreal,
      input.extracted.kind,
      input.extracted.text,
      exactNameCandidate,
      input.now,
    );

    await createProvenanceEdge({
      surreal: input.surreal,
      sourceRecord: input.sourceRecord,
      targetRecord: exactNameCandidate.id,
      confidence: input.extracted.confidence,
      model: input.extractionModelId,
      now: input.now,
      fromText: input.extracted.text,
      evidence: input.extracted.evidence,
      evidenceSourceRecord: input.sourceMessageRecord,
      resolvedFromRecord: input.resolvedFromMessageRecord,
    });

    return {
      record: exactNameCandidate.id,
      text: mergedText,
      kind: input.extracted.kind,
      created: false,
    };
  }

  let bestCandidate: CandidateEntityRow | undefined;
  let bestSimilarity = -1;

  for (const candidate of candidates) {
    if (!candidate.embedding || !candidateEmbedding) {
      continue;
    }

    const similarity = cosineSimilarity(candidateEmbedding, candidate.embedding);
    if (similarity > bestSimilarity) {
      bestSimilarity = similarity;
      bestCandidate = candidate;
    }
  }

  const fuzzyMatch = bestCandidate
    ? isFuzzyNameMatch(normalizeName(input.extracted.text), normalizeName(bestCandidate.text))
    : false;

  if (bestCandidate && bestSimilarity > 0.95 && fuzzyMatch) {
    const mergedText = await maybeUpgradeMergedEntityName(
      input.surreal,
      input.extracted.kind,
      input.extracted.text,
      bestCandidate,
      input.now,
    );

    await createProvenanceEdge({
      surreal: input.surreal,
      sourceRecord: input.sourceRecord,
      targetRecord: bestCandidate.id,
      confidence: input.extracted.confidence,
      model: input.extractionModelId,
      now: input.now,
      fromText: input.extracted.text,
      evidence: input.extracted.evidence,
      evidenceSourceRecord: input.sourceMessageRecord,
      resolvedFromRecord: input.resolvedFromMessageRecord,
    });

    return {
      record: bestCandidate.id,
      text: mergedText,
      kind: input.extracted.kind,
      created: false,
    };
  }

  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
  await input.surreal.create(entityRecord).content(
    buildEntityRecordContent(
      input.extracted.kind,
      input.extracted.text,
      input.extracted.confidence,
      input.now,
      candidateEmbedding,
      input.sourceMessageRecord,
      input.sourceCommitRecord,
      input.extracted.category,
      input.extracted.priority,
      input.workspaceRecord,
    ),
  );

  await createProvenanceEdge({
    surreal: input.surreal,
    sourceRecord: input.sourceRecord,
    targetRecord: entityRecord,
    confidence: input.extracted.confidence,
    model: input.extractionModelId,
    now: input.now,
    fromText: input.extracted.text,
    evidence: input.extracted.evidence,
    evidenceSourceRecord: input.sourceMessageRecord,
    resolvedFromRecord: input.resolvedFromMessageRecord,
  });

  if (input.extracted.kind === "project") {
    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
    input.workspaceProjects.push({
      id: entityRecord as RecordId<"project", string>,
      name: input.extracted.text,
    });
  }

  if (input.extracted.kind === "feature") {
    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
    if (projectRecord) {
      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
    }
  }

  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
    if (projectRecord) {
      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
        added_at: input.now,
      }).output("after");
    }
  }

  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
      kind: "POSSIBLE_DUPLICATE",
      confidence: bestSimilarity,
      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
      ...(input.sourceCommitRecord ? { source_commit: input.sourceCommitRecord } : {}),
      extracted_at: input.now,
      created_at: input.now,
      from_text: input.extracted.text,
      to_text: bestCandidate.text,
    }).output("after");
  }

  return {
    record: entityRecord,
    text: input.extracted.text,
    kind: input.extracted.kind,
    created: true,
  };
}

export async function maybeUpgradeMergedEntityName(
  surreal: Surreal,
  kind: PersistableExtractableEntityKind,
  incomingText: string,
  candidate: CandidateEntityRow,
  now: Date,
): Promise<string> {
  if (!isRicherEntityName(incomingText, candidate.text)) {
    return candidate.text;
  }

  if (kind === "project" || kind === "feature") {
    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
      name: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  if (kind === "task") {
    await surreal.update(candidate.id as RecordId<"task", string>).merge({
      title: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  if (kind === "decision") {
    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
      summary: incomingText,
      updated_at: now,
    });
    return incomingText;
  }

  await surreal.update(candidate.id as RecordId<"question", string>).merge({
    text: incomingText,
    updated_at: now,
  });

  return incomingText;
}

export async function createProvenanceEdge(input: {
  surreal: Surreal;
  sourceRecord: SourceRecord;
  targetRecord: GraphEntityRecord;
  confidence: number;
  model: string;
  now: Date;
  fromText: string;
  evidence: string;
  evidenceSourceRecord?: RecordId<"message", string>;
  resolvedFromRecord?: RecordId<"message", string>;
}): Promise<void> {
  await input.surreal.relate(input.sourceRecord, new RecordId("extraction_relation", randomUUID()), input.targetRecord, {
    confidence: input.confidence,
    extracted_at: input.now,
    created_at: input.now,
    model: input.model,
    from_text: input.fromText,
    evidence: input.evidence,
    ...(input.evidenceSourceRecord ? { evidence_source: input.evidenceSourceRecord } : {}),
    ...(input.resolvedFromRecord ? { resolved_from: input.resolvedFromRecord } : {}),
  }).output("after");
}

function buildEntityRecordContent(
  kind: PersistableExtractableEntityKind,
  text: string,
  confidence: number,
  now: Date,
  embedding?: number[],
  sourceMessageRecord?: RecordId<"message", string>,
  sourceCommitRecord?: RecordId<"git_commit", string>,
  category?: string,
  priority?: string,
  workspaceRecord: RecordId<"workspace", string>,
): Record<string, unknown> {
  if (kind === "project") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "feature") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "task") {
    return {
      title: text,
      status: "open",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "decision") {
    return {
      summary: text,
      status: "extracted",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  // question (fallthrough)
  return {
    text,
    status: "open",
    extraction_confidence: confidence,
    extracted_at: now,
    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
    ...(embedding ? { embedding } : {}),
    ...(category ? { category } : {}),
    ...(priority ? { priority } : {}),
    ...(workspaceRecord ? { workspace: workspaceRecord } : {}),
    created_at: now,
    updated_at: now,
  };
}

export async function loadWorkspaceKindCandidates(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  kind: ExtractableEntityKind,
): Promise<CandidateEntityRow[]> {
  if (kind === "project") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "person") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "feature") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        [
          "SELECT id, name AS text, embedding",
          "FROM feature",
          "WHERE id IN (",
          "  SELECT VALUE out",
          "  FROM has_feature",
          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
          ");",
        ].join(" "),
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "task") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, title AS text, embedding FROM task WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  if (kind === "decision") {
    const [rows] = await surreal
      .query<[CandidateEntityRow[]]>(
        "SELECT id, summary AS text, embedding FROM decision WHERE workspace = $workspace;",
        { workspace: workspaceRecord },
      )
      .collect<[CandidateEntityRow[]]>();
    return rows;
  }

  const [rows] = await surreal
    .query<[CandidateEntityRow[]]>(
      "SELECT id, text AS text, embedding FROM question WHERE workspace = $workspace;",
      { workspace: workspaceRecord },
    )
    .collect<[CandidateEntityRow[]]>();
  return rows;
}

export async function appendWorkspaceTools(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  toolsToAdd: string[],
  now: Date,
): Promise<void> {
  const [rows] = await surreal
    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
      workspace: workspaceRecord,
    })
    .collect<[Array<{ tools?: string[] }>]>();

  const existingTools = rows[0]?.tools ?? [];
  const merged = [...new Set([...existingTools, ...toolsToAdd])];
  await surreal.update(workspaceRecord).merge({
    tools: merged,
    updated_at: now,
  });
}

export function normalizeRelationshipKind(value: string): string {
  return value
    .trim()
    .replace(/[^a-zA-Z0-9]+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_/, "")
    .replace(/_$/, "")
    .toUpperCase();
}

function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) {
    return -1;
  }

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i += 1) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  if (normA === 0 || normB === 0) {
    return -1;
  }

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

